export const StatisticsIcon = (
  properties: MaterialCommunityIconsProps & { name: MaterialCommunityIconName },
) => <MaterialCommunityIcons {...properties} />;

export const ArticleViewIcon = ({ ...rest }: MaterialCommunityIconsProps) => (
  <MaterialCommunityIcons {...rest} name="eye-outline" />
);

export type ChevronDirection = "left" | "right" | "up" | "down";

export const ChevronIcon = ({
  direction,
  size = 30,
  color,
  style,
}: IconProperties & { direction: ChevronDirection }) => {
  const name =
    direction === "left"
      ? "chevron-left"
      : direction === "right"
        ? "chevron-right"
        : direction === "up"
          ? "keyboard-arrow-up"
          : "keyboard-arrow-down";

  return <MaterialIcons name={name} size={size} color={color} style={style} />;
};

export const ReportStatusIcon = ({
  status,
  ...rest
}: FontAwesomeProps & { status: "error" | "posted" | "pending" }) => (
  <FontAwesome
    {...rest}
    name={
      status === "error"
        ? "exclamation-circle"
        : status === "posted"
          ? "check"
          : "hourglass-half"
    }
  />
);

export const ShareIcon = (properties: IconProperties) => (
  <EvilIcons
    name={Platform.OS === "ios" ? "share-apple" : "share-google"}
    size={properties.size ?? 30}
    color={properties.color}
    style={{ lineHeight: properties.size ?? 30 }}
  />
);

export const StarIcon = ({
  filled = false,
  size,
  ...rest
}: IconProperties & { filled?: boolean }) => (
  <FontAwesome {...rest} name={filled ? "star" : "star-o"} size={size ?? 30} />
);

export const SettingsIcon = ({ size, color, ...rest }: IconProperties) => (
  <MaterialCommunityIcons
    {...rest}
    name="cog-outline"
    size={size ?? 30}
    color={color}
  />
);
